#include <bits/stdc++.h>
using namespace std;

const int N=302;

int n,m,q,s[N][N][102],c[N][N][102],a[N][N];

int lowbit(int x){
    return x&(-x);
}

int sum(int x,int y,int k){
    int px=x,sum=0;
    while(px>0){
        int py=y;
        while(py>0){
            sum+=c[px][py][k];
            py-=lowbit(py);
        }
        px-=lowbit(px);
    }
    return sum;
}

void modify(int x,int y,int k){
    int px=x;
    while(px<=n){
        int py=y;
        while(py<=m){
            c[px][py][k]++,c[px][py][a[x][y]]--;
            py+=lowbit(py);
        }
        px+=lowbit(px);
    }
    a[x][y]=k;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            for(int k=1;k<=100;k++)
                s[i][j][k]=s[i-1][j][k]+s[i][j-1][k]-s[i-1][j-1][k]+(k==a[i][j]);
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=1;k<=100;k++)
                c[i][j][k]=s[i][j][k]-s[i-lowbit(i)][j][k]-s[i][j-lowbit(j)][k]+s[i-lowbit(i)][j-lowbit(j)][k];
    scanf("%d",&q);
    while(q--){
        int op;
        scanf("%d",&op);
        if(op==1){
            int x,y,k;
            scanf("%d%d%d",&x,&y,&k);
            modify(x,y,k);
        }else{
            int x,y,u,v,k;
            scanf("%d%d%d%d%d",&x,&u,&y,&v,&k);
            printf("%d\n",sum(u,v,k)-sum(x-1,v,k)-sum(u,y-1,k)+sum(x-1,y-1,k));
        }
    }
    return 0;
}
